import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import axiosInstance from '../axiosConfig';

const ManageTables = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [tables, setTables] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [editingTable, setEditingTable] = useState(null);
  const [formData, setFormData] = useState({
    seats: '',
    location: '',
    babyHighChair: false,
    status: 'available'
  });

  useEffect(() => {
    if (!user) navigate('/login');
  }, [user, navigate]);

  // Fetch all tables
  useEffect(() => {
    const fetchTables = async () => {
      setLoading(true);
      try {
        const response = await axiosInstance.get('/api/tables');
        setTables(response.data);
      } catch (err) {
        setError('Failed to load tables.');
      } finally {
        setLoading(false);
      }
    };
    if (user) fetchTables();
  }, [user]);

  const resetForm = () => {
    setFormData({ seats: '', location: '', babyHighChair: false, status: 'available' });
    setEditingTable(null);
    setShowForm(false);
  };

  const handleEdit = (table) => {
    setEditingTable(table);
    setFormData({
      seats: table.seats,
      location: table.location,
      babyHighChair: table.babyHighChair,
      status: table.status
    });
    setShowForm(true);
  };

  // Create or update table
  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');
    try {
      if (editingTable) {
        const response = await axiosInstance.put(
          `/api/tables/${editingTable._id}`,
          formData,
          { headers: { Authorization: `Bearer ${user.token}` } }
        );
        setTables(tables.map(t => t._id === editingTable._id ? response.data : t));
        setSuccess('Table updated successfully.');
      } else {
        const response = await axiosInstance.post(
          '/api/tables',
          formData,
          { headers: { Authorization: `Bearer ${user.token}` } }
        );
        setTables([...tables, response.data]);
        setSuccess('Table added successfully.');
      }
      resetForm();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to save table.');
    }
  };

  // Delete table
  const handleDelete = async (id) => {
    if (!window.confirm('Delete this table?')) return;
    try {
      await axiosInstance.delete(`/api/tables/${id}`, {
        headers: { Authorization: `Bearer ${user.token}` }
      });
      setTables(tables.filter(t => t._id !== id));
      setSuccess('Table deleted.');
    } catch (err) {
      setError('Failed to delete table.');
    }
  };

  if (loading) return (
    <div className="text-center mt-20 text-gray-500">Loading tables...</div>
  );

  return (
    <div className="max-w-4xl mx-auto mt-10 px-4">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-bold text-blue-700">Manage Tables</h1>
        <button
          onClick={() => { resetForm(); setShowForm(true); }}
          className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700 transition"
        >
          + Add Table
        </button>
      </div>

      {error && (
        <div className="bg-red-100 text-red-700 p-3 rounded mb-4 text-sm">{error}</div>
      )}
      {success && (
        <div className="bg-green-100 text-green-700 p-3 rounded mb-4 text-sm">{success}</div>
      )}

      {/* Add/Edit form */}
      {showForm && (
        <form onSubmit={handleSubmit} className="bg-white p-6 shadow rounded mb-6">
          <h2 className="text-xl font-semibold mb-4">
            {editingTable ? 'Edit Table' : 'Add New Table'}
          </h2>
          <label className="block text-sm font-medium mb-1">Location / Name</label>
          <input
            type="text"
            placeholder="e.g. Window, Outdoor, Private Room"
            value={formData.location}
            onChange={(e) => setFormData({ ...formData, location: e.target.value })}
            className="w-full mb-4 p-2 border rounded"
            required
          />
          <label className="block text-sm font-medium mb-1">Number of Seats</label>
          <input
            type="number"
            min="1"
            value={formData.seats}
            onChange={(e) => setFormData({ ...formData, seats: e.target.value })}
            className="w-full mb-4 p-2 border rounded"
            required
          />
          <label className="block text-sm font-medium mb-1">Status</label>
          <select
            value={formData.status}
            onChange={(e) => setFormData({ ...formData, status: e.target.value })}
            className="w-full mb-4 p-2 border rounded"
          >
            <option value="available">Available</option>
            <option value="maintenance">Maintenance</option>
            <option value="closed">Closed</option>
          </select>
          <label className="flex items-center gap-2 mb-4 cursor-pointer">
            <input
              type="checkbox"
              checked={formData.babyHighChair}
              onChange={(e) => setFormData({ ...formData, babyHighChair: e.target.checked })}
              className="w-4 h-4"
            />
            <span className="text-sm">Baby high chair available</span>
          </label>
          <div className="flex gap-3">
            <button
              type="submit"
              className="flex-1 bg-green-600 text-white p-2 rounded hover:bg-green-700 transition"
            >
              {editingTable ? 'Save Changes' : 'Add Table'}
            </button>
            <button
              type="button"
              onClick={resetForm}
              className="flex-1 bg-gray-200 text-gray-700 p-2 rounded hover:bg-gray-300 transition"
            >
              Cancel
            </button>
          </div>
        </form>
      )}

      {/* Tables grid */}
      {tables.length === 0 ? (
        <div className="bg-white p-6 shadow rounded text-center text-gray-500">
          No tables yet. Add one above.
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          {tables.map((table) => (
            <div key={table._id} className="bg-white shadow rounded p-4">
              <div className="flex justify-between items-start mb-2">
                <h3 className="font-semibold text-lg">{table.location}</h3>
                <span className={`px-2 py-1 rounded text-xs font-semibold
                  ${table.status === 'available' ? 'bg-green-100 text-green-700' :
                    table.status === 'maintenance' ? 'bg-yellow-100 text-yellow-700' :
                    'bg-red-100 text-red-700'}`}>
                  {table.status}
                </span>
              </div>
              <p className="text-sm text-gray-600">Seats: {table.seats}</p>
              <p className="text-sm text-gray-600">
                Baby high chair: {table.babyHighChair ? 'Yes' : 'No'}
              </p>
              <div className="flex gap-2 mt-3">
                <button
                  onClick={() => handleEdit(table)}
                  className="flex-1 bg-yellow-500 text-white py-1 rounded hover:bg-yellow-600 transition text-sm"
                >
                  Edit
                </button>
                <button
                  onClick={() => handleDelete(table._id)}
                  className="flex-1 bg-red-500 text-white py-1 rounded hover:bg-red-600 transition text-sm"
                >
                  Delete
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default ManageTables;
